sql:
SELECT one_mile_average
FROM proximity_1mile
WHERE facility_id = 0 AND variable_id = 1;

SELECT national_average
FROM national_averages
WHERE year = 2021;

SELECT five_mile_average
FROM proximity_5mile
WHERE facility_id = 1;

SELECT state_average
FROM state_averages
WHERE variable_id = 0 AND year = 2020;

SELECT variable_name
FROM demographic_variables
WHERE variable_type = 'economic';

SELECT ten_mile_average
FROM proximity_10mile
WHERE facility_id = 1;

SELECT AVG(value) AS average_value
FROM facility_demographics
WHERE variable_id = 1 AND year = 2020;

SELECT COUNT(*) AS record_count
FROM national_averages
WHERE year = 2020;

SELECT three_mile_average AS average_value
FROM proximity_3mile
WHERE facility_id = 1 AND variable_id = 1;
